package com.example.nofiltercoffee; import android.os.*; import android.widget.*; import androidx.appcompat.app.*;
public class ProfileActivity extends AppCompatActivity{protected void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.simple_page);findViewById(R.id.btnBack).setOnClickListener(v->finish());((TextView)findViewById(R.id.txtTitle)).setText("Profile");((TextView)findViewById(R.id.txtBody)).setText("Name: "+UserSession.getName(this)+"\nPhone: "+UserSession.getPhone(this)+"\nEmail: "+UserSession.getEmail(this)+"\nCoffee Beans: "+UserSession.getCoffeeBeans(this)+"\nWallet: Rs. "+UserSession.getWalletBalance(this));}}
